text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시각",
        "decision": "스모크 테스트 통과 시 금요일 15:00 KST 공개 릴리스",
        "condition": "스모크 테스트 통과"
      },
      {
        "topic": "packageName 불일치 대응 원칙",
        "decision": "불일치 발생 시 먼저 패키지 설정/계약을 확인하고, 계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 검토"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "result": "기각"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 스트레치 목표(확정 일정 아님)"
      }
    ],
    "non_decisions": [
      "README 설치 절차 검토는 필요 제안만 있었고 담당자 확정 없음",
      "Hara의 tarball 경로 점검은 수행 합의가 있으나 정확한 마감 시각 미확정"
    ],
    "risks": [
      "tarball 경로 오류 시 릴리스 지연 가능",
      "README 설치 절차가 오래된 경우 릴리스 노트가 사용자에게 오해를 줄 수 있음"
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 스트레치 목표를 명시할 것인가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "대기",
      "source_certainty": "확정"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "대기",
      "source_certainty": "확정"
    },
    {
      "owner": null,
      "task": "README 설치 단계 검토",
      "due": "목요일(가능하면)",
      "status": "담당자 미지정",
      "source_certainty": "제안(미확정)"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로 점검",
      "due": "미정",
      "status": "선행조건 대기",
      "source_certainty": "확정(마감 미확정)"
    }
  ],
  "followup_note": {
    "next_checks": [
      "금요일 10:00 KST 이전 Minjun 스모크 결과 수신 여부 확인",
      "금요일 12:00 KST까지 Doyun의 action_items.md 트리아지 노트 반영 여부 확인",
      "스모크 통과 시 금요일 15:00 KST 공개 릴리스 게이트 충족 여부 점검",
      "README 설치 단계 검토 담당자 지정 필요",
      "최종 릴리스 승인 권한자 결정 필요",
      "릴리스 노트에 수요일 스트레치 목표 언급 여부 결정 필요"
    ],
    "do_not_invent": [
      "고객/외부 파트너 정보",
      "예산 정보",
      "보안 사고 정보",
      "프로덕션 장애 정보",
      "법무 승인 필요 여부",
      "미지정된 담당자/마감의 임의 확정"
    ]
  },
  "non_invention_rules": [
    "본 출력은 제공된 PUBLIC-SAFE SYNTHETIC MEETING FIXTURE의 명시 내용만 사용한다.",
    "명시되지 않은 고객, 예산, 보안, 장애, 법무, 담당자, 마감 정보를 추가하지 않는다.",
    "확정/기각/미결 상태를 구분하여 기록하고, 추정은 source_certainty로 표시한다."
  ]
}
